            m.BuildString(sb);
            return sb.ToString();
        }

        internal void BuildString(StringBuilder builder)
        {
            if (_buffer == null)
            {
                throw new ArgumentNullException("_buffer");
            }

            int originalLimit = this.Limit;
            this.Limit = _offset + _actingBlockLength;
            builder.Append("[AccountResponseMessage](sbeTemplateId=");
            builder.Append(AccountResponseMessage.TemplateId);
            builder.Append("|sbeSchemaId=");
            builder.Append(AccountResponseMessage.SchemaId);
            builder.Append("|sbeSchemaVersion=");
            if (_parentMessage._actingVersion != AccountResponseMessage.SchemaVersion)
            {
                builder.Append(_parentMessage._actingVersion);
                builder.Append('/');
            }
            builder.Append(AccountResponseMessage.SchemaVersion);
            builder.Append("|sbeBlockLength=");
            if (_actingBlockLength != AccountResponseMessage.BlockLength)
            {
                builder.Append(_actingBlockLength);
                builder.Append('/');
            }
            builder.Append(AccountResponseMessage.BlockLength);
            builder.Append("):");

            builder.Append("RequestId=");
            builder.Append(this.RequestId);
            builder.Append('|');
            builder.Append("Count=");
            builder.Append(this.Count);
            builder.Append('|');
            builder.Append("Accounts=[");
            var accounts = this.Accounts;
            if (accounts.Count > 0)
            {
                var first = true;
                while (accounts.HasNext)
                {
                    if (!first)
                    {
                        builder.Append(',');
                    }
                    first = false;
                    accounts.Next().BuildString(builder);
                }
            }
            builder.Append("]");

            this.Limit = originalLimit;

        }
    }
}
